// Determine notification type and prepare message
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json.exportedData || item.json.conflictData || item.json.invalidData || item.json;
  const notificationType = item.json.notificationType || 'event_created';

  let subject = '';
  let messageBody = '';
  let recipients = [];

  // Get requestor email
  const requestorEmail = data.requestorEmail || data.normalized?.attendees?.[0] || '';
  if (requestorEmail) {
    recipients.push(requestorEmail);
  }

  // Build notification based on type
  switch (notificationType) {
    case 'event_created':
      subject = `✅ Meeting Scheduled: ${data.normalized.title}`;
      messageBody = `
Your meeting has been successfully scheduled:

📅 Event: ${data.normalized.title}
🕒 Time: ${new Date(data.normalized.startTime).toLocaleString()}
⏱️ Duration: ${data.normalized.duration} minutes
📍 Location: ${data.normalized.location}
👥 Attendees: ${data.normalized.attendees.join(', ')}

🔗 Calendar Link: ${data.export?.eventUrl || 'Check your calendar'}

Event ID: ${data.export?.eventId || data.requestId}

All attendees have been notified via calendar invitation.
      `;
      break;

    case 'conflict_detected':
      subject = `⚠️ Scheduling Conflict Detected: ${data.normalized.title}`;
      messageBody = `
We detected a conflict with your requested meeting time:

📅 Requested: ${data.normalized.title}
🕒 Time: ${new Date(data.normalized.startTime).toLocaleString()}

❌ Conflicts Found: ${data.conflictScan.conflictCount}

Conflicting Events:
${data.conflictScan.conflicts.map(c => `  • ${c.title} (${new Date(c.start).toLocaleString()} - ${new Date(c.end).toLocaleString()})`).join('\n')}

💡 Suggested Alternative Times:
${data.conflictScan.alternatives.map((alt, idx) => `  ${idx + 1}. ${new Date(alt.startTime).toLocaleString()} - ${alt.reason}`).join('\n')}

Please reply with your preferred alternative time, or suggest a different time.
      `;
      break;

    case 'validation_failed':
      subject = `❌ Scheduling Request Failed: ${data.normalized?.title || 'Meeting'}`;
      messageBody = `
Your scheduling request could not be processed due to validation errors:

📅 Requested: ${data.normalized?.title || 'Meeting'}
🕒 Time: ${data.normalized?.startTime ? new Date(data.normalized.startTime).toLocaleString() : 'Not specified'}

❌ Errors:
${data.validation.errors.map(e => `  • ${e}`).join('\n')}

${data.validation.warnings.length > 0 ? `⚠️ Warnings:\n${data.validation.warnings.map(w => `  • ${w}`).join('\n')}` : ''}

Please review the errors and submit a corrected request.
      `;
      break;

    default:
      subject = `Meeting Update: ${data.normalized?.title || 'Notification'}`;
      messageBody = `
Your scheduling request has been processed.

Request ID: ${data.requestId}
Status: ${data.status}
      `;
  }

  const notificationData = {
    ...data,
    notification: {
      type: notificationType,
      subject: subject,
      body: messageBody,
      recipients: recipients,
      preparedAt: new Date().toISOString(),
      confirmationCode: `CONF-${Date.now()}`
    },
    stage: 'notification_prepared',
    processedAt: new Date().toISOString()
  };

  results.push({ json: notificationData });
}

return results;

// Log notification delivery
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const finalResult = {
    ...data,
    notification: {
      ...data.notification,
      sent: true,
      sentAt: new Date().toISOString(),
      deliveryStatus: 'success'
    },
    stage: 'completed',
    completedAt: new Date().toISOString(),
    summary: {
      requestId: data.requestId,
      status: data.status,
      notificationType: data.notification.type,
      recipients: data.notification.recipients,
      processingTime: new Date() - new Date(data.timestamp)
    }
  };

  results.push({ json: finalResult });
}

return results;
